const express = require('express');
const axios = require('axios');

const app = express();
const port = 3000;

app.use(express.json());

// In-memory cache for NIN verification results
const ninCache = new Map();

app.post('/api/verify-nin', async (req, res) => {
  const { nin } = req.body;

  if (!nin) {
    return res.status(400).json({ error: 'NIN is required' });
  }

  // Check cache first
  if (ninCache.has(nin)) {
    console.log(`Cache hit for NIN: ${nin}`);
    return res.json(ninCache.get(nin));
  }

  try {
    const appId = process.env.PREMBLY_APP_ID;
    const apiKey = process.env.PREMBLY_API_KEY;

    if (!appId || !apiKey) {
      return res.status(500).json({ error: 'Prembly API credentials not configured' });
    }

    const response = await axios.post(
      'https://api.prembly.com/verification/nin',
      { number: nin },
      {
        headers: {
          'app-id': appId,
          'x-api-key': apiKey,
          'Content-Type': 'application/json'
        }
      }
    );

    // Cache the successful response data
    ninCache.set(nin, response.data);
    console.log(`Cache miss for NIN: ${nin}. Result cached.`);

    return res.json(response.data);
  } catch (error) {
    console.error('Error verifying NIN:', error.response ? error.response.data : error.message);
    const statusCode = error.response ? error.response.status : 500;
    const errorMessage = error.response ? error.response.data : 'An error occurred during verification';
    return res.status(statusCode).json(errorMessage);
  }
});

app.listen(port, () => {
  console.log(`NIN Lookup Cache server listening at http://localhost:${port}`);
});

